from __future__ import annotations

from .schemas import ConstraintSpec


def _spec(
    identifier: str,
    category: str,
    template: str,
    params: dict[str, str],
    handler: str,
    tags: tuple[str, ...],
    *,
    normalization_mode: str = "strict_surface",
    single_only: bool = False,
    loose_enabled: bool = True,
) -> ConstraintSpec:
    return ConstraintSpec(
        id=identifier,
        category=category,
        split_role="test",
        description_templates_ar=(template,),
        params_schema=params,
        normalization_mode=normalization_mode,
        conflict_tags=tags,
        single_only=single_only,
        handler=handler,
        loose_enabled=loose_enabled,
    )


